/**
 * @fileoverview DatePicker constants - months, weekdays, segment defs, SVG, CSS classes, defaults.
 * @module module/DatePicker/constants
 */

import { MONTHS_SHORT as _MONTHS_SHORT } from '../shared/tokens/locale.js';
import { ICON_CHEVRON_PREV, ICON_CHEVRON_NEXT } from '../shared/tokens/icons.js';
import { DROPDOWN_GAP_PX } from '../shared/tokens/layout.js';
import Icons from '../Icons.js';
import { TRUNCATE, DISABLED, selectedState, focusRing } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** Abbreviated month names. */
export const MONTHS_SHORT = _MONTHS_SHORT;

/** Two-letter weekday abbreviations (Sunday-first). */
export const WEEKDAYS = Object.freeze(['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa']);

/** Segment type definitions: max display length, min/max values. */
export const SEGMENTS = Object.freeze({
    year:   { len: 4, min: 1900, max: 2199 },
    month:  { len: 2, min: 1, max: 12 },
    day:    { len: 2, min: 1, max: 31 },
    hour:   { len: 2, min: 0, max: 23 },
    minute: { len: 2, min: 0, max: 59 },
});

/** Segment keys per format type. */
export const FORMAT_SEGMENTS = Object.freeze({
    date:     ['year', 'month', 'day'],
    month:    ['year', 'month'],
    datetime: ['year', 'month', 'day', 'hour', 'minute'],
    time:     ['hour', 'minute'],
});

/** SVG icon markup. */
export const SVG = Object.freeze({
    CALENDAR: Icons.svg('calendar', { size: 16, strokeWidth: 1.3 }),
    CLOCK:    Icons.svg('clock', { size: 16, strokeWidth: 1.3 }),
    PREV:     ICON_CHEVRON_PREV,
    NEXT:     ICON_CHEVRON_NEXT,
});

/** CSS class names. */
export const CLS = Object.freeze({
    CONTAINER:    'date-picker',
    SECTION:      'date-picker-section',
    ICON:         'date-picker-icon',
    SEG:          'date-picker-seg',
    SEP:          'date-picker-sep',
    SEP_SPACE:    'date-picker-sep date-picker-sep-space',
    RANGE_SEP:    'date-picker-range-sep',
    DISPLAY:      'date-picker-display',
    POPUP:        'date-picker-popup',
    POPUP_HEADER: 'date-picker-popup-header',
    POPUP_BODY:   'date-picker-popup-body',
    POPUP_FOOTER: 'date-picker-popup-footer',
    NAV:          'date-picker-nav',
    TITLE:        'date-picker-title',
    WEEKDAY:      'date-picker-weekday',
    EMPTY:        'date-picker-empty',
    DAY:          'date-picker-day',
    MONTH_CELL:   'date-picker-month-cell',
    YEAR_CELL:    'date-picker-year-cell',
    TODAY_BTN:    'date-picker-today',
    DISABLED:     'is-disabled',
    TODAY:        'is-today',
    SELECTED:     'is-selected',
    RANGE_START:  'is-range-start',
    RANGE_END:    'is-range-end',
    IN_RANGE:     'is-in-range',
    OUT_OF_RANGE: 'is-out-of-range',
    HAS_VALUE:    'has-value',
    INVALID:      'is-invalid',
});

/** Default configuration values. */
export const DEFAULTS = Object.freeze({
    type:         'date',
    mode:         'single',
    placeholder:  '',
    min:          null,
    max:          null,
    dropdownGap: DROPDOWN_GAP_PX,
});

/** ARIA / UI text strings. */
export const TEXT = Object.freeze({
    TODAY:           'Today',
    OPEN_CALENDAR:   'Open calendar',
    TIME_LABEL:      'Time',
    CALENDAR_DIALOG: 'Calendar',
    PICKER_GROUP:    'Date picker',
    PREVIOUS:        'Previous',
    NEXT:            'Next',
    RANGE_SEP:       '~',
});

/** Semantic part names for JIT styling overrides. */
export const PART = defineParts('DatePicker', {
    CONTAINER   : { class: 'date-picker', aliases: ['container', 'root'] },
    SECTION     : { class: 'date-picker-section', aliases: ['section'] },
    ICON        : { class: 'date-picker-icon', aliases: ['icon'] },
    SEG         : { class: 'date-picker-seg', aliases: ['seg', 'segment'] },
    SEP         : { class: 'date-picker-sep', aliases: ['sep', 'separator'] },
    RANGE_SEP   : { class: 'date-picker-range-sep', aliases: ['range-sep'] },
    POPUP       : { class: 'date-picker-popup', aliases: ['popup'] },
    POPUP_HEADER: { class: 'date-picker-popup-header', aliases: ['popup-header'] },
    NAV         : { class: 'date-picker-nav', aliases: ['nav'] },
    TITLE       : { class: 'date-picker-title', aliases: ['title'] },
    POPUP_BODY  : { class: 'date-picker-popup-body', aliases: ['popup-body'] },
    WEEKDAY     : { class: 'date-picker-weekday', aliases: ['weekday'] },
    EMPTY       : { class: 'date-picker-empty', aliases: ['empty'] },
    DAY         : { class: 'date-picker-day', aliases: ['day'] },
    MONTH_CELL  : { class: 'date-picker-month-cell', aliases: ['month-cell'] },
    YEAR_CELL   : { class: 'date-picker-year-cell', aliases: ['year-cell'] },
    POPUP_FOOTER: { class: 'date-picker-popup-footer', aliases: ['popup-footer'] },
    TODAY_BTN   : { class: 'date-picker-today', aliases: ['today-btn'] },
    DISPLAY     : { class: 'date-picker-display', aliases: ['display'] },
});

PART.CONTAINER.jit = [
'inline-flex items-stretch [width:fit-content] [border:1px_solid_var(--dp-border)] rounded-[var(--dp-radius)] bg-[var(--dp-bg)] [font-family:inherit] text-[var(--dp-font-size)] [line-height:var(--dp-line-height)] [transition:border-color_0.15s_ease,box-shadow_0.15s_ease] cursor-text hover:[border-color:var(--dp-border-strong)] ' + focusRing('dp', '2px', 'focus-within') + ' ' + DISABLED + ' {is-disabled}:bg-[var(--dp-bg-inset)]',
'[&_.date-picker-seg-year]:[width:4ch] [&_.date-picker-seg-year]:[min-width:4ch]',
'[&_.date-picker-seg-month]:[width:2ch] [&_.date-picker-seg-month]:[min-width:2ch] [&_.date-picker-seg-day]:[width:2ch] [&_.date-picker-seg-day]:[min-width:2ch] [&_.date-picker-seg-hour]:[width:2ch] [&_.date-picker-seg-hour]:[min-width:2ch] [&_.date-picker-seg-minute]:[width:2ch] [&_.date-picker-seg-minute]:[min-width:2ch]',
'[&_.date-picker-day:not(.is-out-of-range)]:hover:bg-[var(--dp-bg-hover)]',
'[&_.date-picker-month-cell:hover:not(.is-selected)]:bg-[var(--dp-bg-hover)] [&_.date-picker-year-cell:hover:not(.is-selected)]:bg-[var(--dp-bg-hover)]',
].join(' ');
PART.SECTION.jit  = 'inline-flex items-center [&>.date-picker-icon+.date-picker-seg]:[margin-left:var(--dp-seg-padding-y)] [&>.date-picker-seg:first-child]:[margin-left:var(--dp-seg-padding-y)] [&>.date-picker-seg:last-child]:[margin-right:var(--dp-seg-padding-y)]';
PART.ICON.jit     = 'flex items-center justify-center [appearance:none] [border:none] bg-none fg-[var(--dp-text-muted)] cursor-pointer [padding:var(--dp-control-py)_var(--dp-seg-padding-y)] [border-right:1px_solid_var(--dp-border)] [border-radius:0] [transition:color_0.15s_ease,background_0.15s_ease] shrink-0 hover:fg-[var(--dp-accent)] hover:bg-[var(--dp-bg-hover)]';
PART.SEG.jit      = '[border:none] [outline:none] bg-transparent [box-shadow:none] [border-radius:0] [font-family:var(--dp-font-mono)] [font-size:inherit] [line-height:inherit] fg-[var(--dp-text)] text-center [padding:var(--dp-control-py)_0] placeholder:fg-[var(--dp-text-muted)] placeholder:[font-family:inherit]';
PART.SEP.jit      = 'fg-[var(--dp-text-muted)] text-[0.8em] [user-select:none] shrink-0 [padding:0_1px]';
PART.RANGE_SEP.jit = 'flex items-center [padding:0_var(--dp-seg-padding-y)] fg-[var(--dp-text-muted)] fw-600 text-[0.85em] [user-select:none] shrink-0';
PART.POPUP.jit    = 'fixed bg-[var(--dp-bg)] [border:1px_solid_var(--dp-border)] rounded-[var(--dp-radius)] [box-shadow:var(--dp-shadow-lg)] [font-family:inherit] text-[var(--dp-font-size)] [min-width:260px] [user-select:none]';
PART.POPUP_HEADER.jit = 'flex items-center gap-[var(--dp-space-xs)] [padding:var(--dp-seg-padding-y)] [border-bottom:1px_solid_var(--dp-border)]';
PART.NAV.jit      = 'flex items-center justify-center [appearance:none] [border:none] bg-none fg-[var(--dp-text-muted)] cursor-pointer w-[28px] h-[28px] rounded-[var(--dp-radius)] [transition:background_0.1s_ease,color_0.1s_ease] shrink-0 p-0 hover:bg-[var(--dp-bg-hover)] hover:fg-[var(--dp-text)]';
PART.TITLE.jit    = 'flex-1 text-center [appearance:none] [border:none] bg-none [font-family:inherit] text-[0.85rem] fw-600 fg-[var(--dp-text)] cursor-pointer [padding:var(--dp-space-xs)_var(--dp-seg-padding-y)] rounded-[var(--dp-radius)] [transition:background_0.1s_ease] hover:bg-[var(--dp-bg-hover)]';
PART.POPUP_BODY.jit = '[padding:var(--dp-seg-padding-y)] {is-day}:grid {is-day}:[grid-template-columns:repeat(7,1fr)] {is-day}:gap-[2px] {is-month}:grid {is-month}:[grid-template-columns:repeat(4,1fr)] {is-month}:gap-[4px] {is-year}:grid {is-year}:[grid-template-columns:repeat(4,1fr)] {is-year}:gap-[4px]';
PART.WEEKDAY.jit  = 'text-center text-[0.72rem] fw-600 fg-[var(--dp-text-muted)] [padding:var(--dp-space-xs)_0] uppercase [letter-spacing:0.04em]';
PART.EMPTY.jit    = '[min-height:30px]';
PART.DAY.jit      = 'flex items-center justify-center [appearance:none] [border:none] bg-none w-full [min-height:30px] [font-family:inherit] text-[0.8rem] fg-[var(--dp-text)] cursor-pointer rounded-[var(--dp-radius)] [transition:background_0.1s_ease,color_0.1s_ease] p-0 relative ' + selectedState('dp') + ' {is-out-of-range}:fg-[var(--dp-text-muted)] {is-out-of-range}:[opacity:0.35] {is-out-of-range}:cursor-not-allowed {is-today}:[box-shadow:inset_0_0_0_1px_var(--dp-accent)] {is-in-range}:bg-[var(--dp-accent-subtle)] {is-in-range}:rounded-none';
PART.MONTH_CELL.jit = 'flex items-center justify-center [appearance:none] [border:none] bg-none [font-family:inherit] text-[0.82rem] fg-[var(--dp-text)] cursor-pointer [padding:var(--dp-seg-padding-y)_var(--dp-space-xs)] rounded-[var(--dp-radius)] [transition:background_0.1s_ease,color_0.1s_ease] [min-height:36px] ' + selectedState('dp');
PART.YEAR_CELL.jit = 'flex items-center justify-center [appearance:none] [border:none] bg-none [font-family:inherit] text-[0.82rem] fg-[var(--dp-text)] cursor-pointer [padding:var(--dp-seg-padding-y)_var(--dp-space-xs)] rounded-[var(--dp-radius)] [transition:background_0.1s_ease,color_0.1s_ease] [min-height:36px] ' + selectedState('dp');
PART.POPUP_FOOTER.jit = '[padding:var(--dp-space-xs)_var(--dp-seg-padding-y)] [border-top:1px_solid_var(--dp-border)] flex justify-center';
PART.TODAY_BTN.jit = '[appearance:none] [border:none] bg-none [font-family:inherit] text-[0.78rem] fw-600 fg-[var(--dp-accent)] cursor-pointer [padding:var(--dp-space-xs)_var(--dp-space-md)] rounded-[var(--dp-radius)] [transition:background_0.1s_ease] hover:bg-[var(--dp-accent-subtle)]';
PART.DISPLAY.jit  = TRUNCATE + ' [font-family:inherit] text-[12px] [line-height:22px] fg-[var(--dp-text-muted)] {has-value}:fg-[var(--dp-text)]';